  email: string
  /**
     * Street name
     */
  street: string
  /**
     * Street number
     */
  streetNumber?: string
  /**
     * Όνομα πόλης
     */
  city: string
  /**
     * Ταχυδρομικός κώδικας
     */
  zipcode: string
  /**
     * Country alpha-2 code (e.g., 'GR', 'US')
     */
  countryId: string
  /**
     * Αλφαριθμητικός κωδικός περιφέρειας
     */
  regionId?: string | null
  /**
     * Τηλέφωνο πελάτη
     */
  phone: string
  /**
     * Customer notes or special instructions
     */
